package com.example.student_grade_app.ui.onboarding.preview


import androidx.compose.foundation.layout.*
import androidx.compose.foundation.lazy.LazyColumn
import androidx.compose.foundation.lazy.items
import androidx.compose.foundation.shape.RoundedCornerShape
import androidx.compose.material3.*
import androidx.compose.runtime.*
import androidx.compose.ui.Alignment
import androidx.compose.ui.Modifier
import androidx.compose.ui.text.font.FontWeight
import androidx.compose.ui.unit.dp
import com.example.student_grade_app.model.Student
import com.example.student_grade_app.ui.theme.*
import com.example.student_grade_app.viewmodel.GradeViewModel


@OptIn(ExperimentalMaterial3Api::class)
@Composable
fun PreviewScreen(
    viewModel: GradeViewModel,
    onCalculated: () -> Unit,
    onBack: () -> Unit
) {
    val uiState by viewModel.uiState.collectAsState()

    LaunchedEffect(uiState.calculatedStudents) {
        if (uiState.calculatedStudents.isNotEmpty()) onCalculated()
    }

    Scaffold(
        topBar = {
            TopAppBar(
                title = { Text("Import Preview", color = OffWhite) },
                navigationIcon = {
                    TextButton(onClick = onBack) {
                        Text("Back", color = BluePrimary)
                    }
                },
                colors = TopAppBarDefaults.topAppBarColors(
                    containerColor = DarkSurface
                )
            )
        },
        containerColor = DarkBg
    ) { padding ->

        Column(
            modifier = Modifier
                .fillMaxSize()
                .padding(padding)
                .padding(horizontal = 16.dp)
        ) {

            Spacer(modifier = Modifier.height(12.dp))

            // Summary card
            Card(
                modifier = Modifier.fillMaxWidth(),
                shape = RoundedCornerShape(14.dp),
                colors = CardDefaults.cardColors(containerColor = BlueLight)
            ) {
                Row(
                    modifier = Modifier.padding(16.dp),
                    verticalAlignment = Alignment.CenterVertically
                ) {
                    Column {
                        Text(
                            "${uiState.students.size} Students Found",
                            style = MaterialTheme.typography.titleLarge,
                            color = BluePrimary,
                            fontWeight = FontWeight.Bold
                        )
                        Text(
                            "Review the data below before calculating",
                            style = MaterialTheme.typography.bodyMedium,
                            color = GrayMid
                        )
                    }
                }
            }

            Spacer(modifier = Modifier.height(12.dp))

            LazyColumn(
                modifier = Modifier.weight(1f),
                verticalArrangement = Arrangement.spacedBy(10.dp),
                contentPadding = PaddingValues(bottom = 16.dp)
            ) {
                items(uiState.students) { student ->
                    StudentPreviewCard(student)
                }
            }

            Button(
                onClick = { viewModel.calculateGrades() },
                modifier = Modifier
                    .fillMaxWidth()
                    .navigationBarsPadding()
                    .padding(vertical = 12.dp)
                    .height(54.dp),
                shape = RoundedCornerShape(14.dp),
                colors = ButtonDefaults.buttonColors(containerColor = BluePrimary)
            ) {
                Text(
                    "Calculate Grades",
                    style = MaterialTheme.typography.labelLarge,
                    color = DarkBg
                )
            }
        }
    }
}

@Composable
private fun StudentPreviewCard(student: Student) {
    Card(
        modifier = Modifier.fillMaxWidth(),
        shape = RoundedCornerShape(12.dp),
        colors = CardDefaults.cardColors(containerColor = DarkSurface),
        elevation = CardDefaults.cardElevation(defaultElevation = 0.dp)
    ) {
        Column(modifier = Modifier.padding(16.dp)) {
            Text(
                text = student.name,
                style = MaterialTheme.typography.titleLarge,
                color = OffWhite
            )
            Spacer(modifier = Modifier.height(6.dp))
            Text(
                text = "Scores: ${student.scores.joinToString("   |   ")}",
                style = MaterialTheme.typography.bodyMedium,
                color = GrayMid
            )
        }
    }
}

package com.example.student_grade_app.ui.onboarding.preview


import androidx.compose.foundation.layout.*
import androidx.compose.foundation.lazy.LazyColumn
import androidx.compose.foundation.lazy.items
import androidx.compose.foundation.shape.RoundedCornerShape
import androidx.compose.material3.*
import androidx.compose.runtime.*
import androidx.compose.ui.Alignment
import androidx.compose.ui.Modifier
import androidx.compose.ui.text.font.FontWeight
import androidx.compose.ui.unit.dp
import com.example.student_grade_app.model.Student
import com.example.student_grade_app.ui.theme.*
import com.example.student_grade_app.viewmodel.GradeViewModel


@OptIn(ExperimentalMaterial3Api::class)
@Composable
fun PreviewScreen(
    viewModel: GradeViewModel,
    onCalculated: () -> Unit,
    onBack: () -> Unit
) {
    val uiState by viewModel.uiState.collectAsState()

    // Use a one-time navigation flag so Preview only navigates to Results when
    // a calculation just happened. This prevents the "flicker" where
    // returning to Preview immediately navigates forward again.
    LaunchedEffect(uiState.navigateToResults) {
        if (uiState.navigateToResults) {
            onCalculated()
            viewModel.clearNavigateToResults()
        }
    }

    Scaffold(
        topBar = {
            TopAppBar(
                title = { Text("Import Preview", color = OffWhite) },
                navigationIcon = {
                    TextButton(onClick = onBack) {
                        Text("Back", color = BluePrimary)
                    }
                },
                colors = TopAppBarDefaults.topAppBarColors(
                    containerColor = DarkSurface
                )
            )
        },
        containerColor = DarkBg
    ) { padding ->

        Column(
            modifier = Modifier
                .fillMaxSize()
                .padding(padding)
                .padding(horizontal = 16.dp)
        ) {

            Spacer(modifier = Modifier.height(12.dp))

            // Summary card
            Card(
                modifier = Modifier.fillMaxWidth(),
                shape = RoundedCornerShape(14.dp),
                colors = CardDefaults.cardColors(containerColor = BlueLight)
            ) {
                Row(
                    modifier = Modifier.padding(16.dp),
                    verticalAlignment = Alignment.CenterVertically
                ) {
                    Column {
                        Text(
                            "${uiState.students.size} Students Found",
                            style = MaterialTheme.typography.titleLarge,
                            color = BluePrimary,
                            fontWeight = FontWeight.Bold
                        )
                        Text(
                            "Review the data below before calculating",
                            style = MaterialTheme.typography.bodyMedium,
                            color = GrayMid
                        )
                    }
                }
            }

            Spacer(modifier = Modifier.height(12.dp))

            LazyColumn(
                modifier = Modifier.weight(1f),
                verticalArrangement = Arrangement.spacedBy(10.dp),
                contentPadding = PaddingValues(bottom = 16.dp)
            ) {
                items(uiState.students) { student ->
                    StudentPreviewCard(student)
                }
            }

            Button(
                onClick = { viewModel.calculateGrades() },
                modifier = Modifier
                    .fillMaxWidth()
                    .navigationBarsPadding()
                    .padding(vertical = 12.dp)
                    .height(54.dp),
                shape = RoundedCornerShape(14.dp),
                colors = ButtonDefaults.buttonColors(containerColor = BluePrimary)
            ) {
                Text(
                    "Calculate Grades",
                    style = MaterialTheme.typography.labelLarge,
                    color = DarkBg
                )
            }
        }
    }
}

@Composable
private fun StudentPreviewCard(student: Student) {
    Card(
        modifier = Modifier.fillMaxWidth(),
        shape = RoundedCornerShape(12.dp),
        colors = CardDefaults.cardColors(containerColor = DarkSurface),
        elevation = CardDefaults.cardElevation(defaultElevation = 0.dp)
    ) {
        Column(modifier = Modifier.padding(16.dp)) {
            Text(
                text = student.name,
                style = MaterialTheme.typography.titleLarge,
                color = OffWhite
            )
            Spacer(modifier = Modifier.height(6.dp))
            Text(
                text = "Scores: ${student.scores.joinToString("   |   ")}",
                style = MaterialTheme.typography.bodyMedium,
                color = GrayMid
            )
        }
    }
}

package com.example.student_grade_app.ui.onboarding.results

import androidx.compose.foundation.background
import androidx.compose.foundation.layout.*
import androidx.compose.foundation.lazy.LazyColumn
import androidx.compose.foundation.lazy.items
import androidx.compose.foundation.shape.RoundedCornerShape
import androidx.compose.material3.*
import androidx.compose.runtime.*
import androidx.compose.ui.Alignment
import androidx.compose.ui.Modifier
import androidx.compose.ui.graphics.Color
import androidx.compose.ui.platform.LocalContext
import androidx.compose.ui.text.font.FontWeight
import androidx.compose.ui.unit.dp
import androidx.compose.ui.unit.sp
import com.example.student_grade_app.model.Student
import com.example.student_grade_app.ui.theme.*
import com.example.student_grade_app.viewmodel.GradeViewModel

@OptIn(ExperimentalMaterial3Api::class)
@Composable
fun ResultsScreen(
    viewModel : GradeViewModel,
    onBack    : () -> Unit
) {
    val context           = LocalContext.current
    val uiState           by viewModel.uiState.collectAsState()
    val snackbarHostState = remember { SnackbarHostState() }

    LaunchedEffect(uiState.exportSuccess) {
        if (uiState.exportSuccess) {
            snackbarHostState.showSnackbar("Results ready — choose where to save")
            viewModel.clearExportSuccess()
        }
    }

    Scaffold(
        topBar = {
            TopAppBar(
                title           = { Text("Results", color = OffWhite) },
                navigationIcon  = {
                    TextButton(onClick = onBack) {
                        Text("Back", color = BluePrimary)
                    }
                },
                colors = TopAppBarDefaults.topAppBarColors(containerColor = DarkSurface)
            )
        },
        snackbarHost   = { SnackbarHost(snackbarHostState) },
        containerColor = DarkBg
    ) { padding ->

        Column(
            modifier = Modifier
                .fillMaxSize()
                .padding(padding)
                .padding(horizontal = 16.dp)
        ) {
            Spacer(modifier = Modifier.height(12.dp))

            SummaryCard(students = uiState.calculatedStudents)

            Spacer(modifier = Modifier.height(12.dp))

            LazyColumn(
                modifier            = Modifier.weight(1f),
                verticalArrangement = Arrangement.spacedBy(10.dp),
                contentPadding      = PaddingValues(bottom = 16.dp)
            ) {
                items(uiState.calculatedStudents) { student ->
                    ResultCard(student)
                }
            }

            // Export button — triggers ShareSheet, no save picker needed
            if (uiState.isExporting) {
                Box(
                    modifier         = Modifier.fillMaxWidth(),
                    contentAlignment = Alignment.Center
                ) {
                    CircularProgressIndicator(color = BluePrimary)
                }
            } else {
                Button(
                    onClick  = { viewModel.exportResults(context) },  // ← simple!
                    modifier = Modifier
                        .fillMaxWidth()
                        .navigationBarsPadding()
                        .padding(vertical = 12.dp)
                        .height(54.dp),
                    shape  = RoundedCornerShape(14.dp),
                    colors = ButtonDefaults.buttonColors(containerColor = BlueDeep)
                ) {
                    Text(
                        "Export to Excel",
                        style = MaterialTheme.typography.labelLarge,
                        color = White
                    )
                }
            }
        }
    }
}

// ── Summary stats card ─────────────────────────────────────────────────────

@Composable
private fun SummaryCard(students: List<Student>) {
    val passCount = students.count { it.passed == true }
    val failCount = students.size - passCount

    Card(
        modifier = Modifier.fillMaxWidth(),
        shape    = RoundedCornerShape(16.dp),
        colors   = CardDefaults.cardColors(containerColor = BlueLight)
    ) {
        Row(
            modifier              = Modifier
                .fillMaxWidth()
                .padding(20.dp),
            horizontalArrangement = Arrangement.SpaceEvenly
        ) {
            StatItem(label = "Total", value = "${students.size}", color = OffWhite)
            StatItem(label = "Pass",  value = "$passCount",       color = AccentGreen)
            StatItem(label = "Fail",  value = "$failCount",       color = AccentRed)
        }
    }
}

@Composable
private fun StatItem(label: String, value: String, color: Color) {
    Column(horizontalAlignment = Alignment.CenterHorizontally) {
        Text(value, fontSize = 28.sp, fontWeight = FontWeight.Bold, color = color)
        Text(label, style = MaterialTheme.typography.bodyMedium, color = GrayMid)
    }
}

// ── Individual result card ─────────────────────────────────────────────────

@Composable
private fun ResultCard(student: Student) {
    val gradeColor = when (student.grade) {
        "A"  -> GradeA
        "B+" -> GradeB
        "B"  -> GradeB
        "C+" -> GradeC
        "C"  -> GradeC
        "D+" -> GradeD
        "D"  -> GradeD
        else -> GradeF
    }
    val statusColor = if (student.passed == true) AccentGreen else AccentRed

    Card(
        modifier  = Modifier.fillMaxWidth(),
        shape     = RoundedCornerShape(14.dp),
        colors    = CardDefaults.cardColors(containerColor = DarkSurface),
        elevation = CardDefaults.cardElevation(defaultElevation = 0.dp)
    ) {
        Row(
            modifier          = Modifier
                .fillMaxWidth()
                .padding(16.dp),
            verticalAlignment = Alignment.CenterVertically
        ) {
            // Grade badge
            Box(
                modifier         = Modifier
                    .size(52.dp)
                    .background(gradeColor.copy(alpha = 0.15f), RoundedCornerShape(12.dp)),
                contentAlignment = Alignment.Center
            ) {
                Text(
                    text       = student.grade ?: "-",
                    fontSize   = 18.sp,         // slightly smaller to fit "B+" "C+" etc
                    fontWeight = FontWeight.Bold,
                    color      = gradeColor
                )
            }

            Spacer(modifier = Modifier.width(14.dp))

            Column(modifier = Modifier.weight(1f)) {
                Text(
                    student.name,
                    style = MaterialTheme.typography.titleLarge,
                    color = OffWhite
                )
                Text(
                    "Average: ${"%.1f".format(student.average ?: 0.0)}",
                    style = MaterialTheme.typography.bodyMedium,
                    color = GrayMid
                )
            }

            // Pass / Fail chip
            Surface(
                shape = RoundedCornerShape(50),
                color = statusColor.copy(alpha = 0.15f)
            ) {
                Text(
                    text       = if (student.passed == true) "PASS" else "FAIL",
                    color      = statusColor,
                    fontWeight = FontWeight.Bold,
                    fontSize   = 12.sp,
                    modifier   = Modifier.padding(horizontal = 12.dp, vertical = 5.dp)
                )
            }
        }
    }
}

package com.example.student_grade_app.ui.onboarding.results

import androidx.compose.foundation.background
import androidx.compose.foundation.layout.*
import androidx.compose.foundation.lazy.LazyColumn
import androidx.compose.foundation.lazy.items
import androidx.compose.foundation.shape.RoundedCornerShape
import androidx.compose.material3.*
import androidx.compose.runtime.*
import androidx.compose.ui.Alignment
import androidx.compose.ui.Modifier
import androidx.compose.ui.graphics.Color
import androidx.compose.ui.platform.LocalContext
import androidx.compose.ui.text.font.FontWeight
import androidx.compose.ui.unit.dp
import androidx.compose.ui.unit.sp
import com.example.student_grade_app.model.Student
import com.example.student_grade_app.ui.theme.*
import com.example.student_grade_app.viewmodel.GradeViewModel
import android.widget.Toast

@OptIn(ExperimentalMaterial3Api::class)
@Composable
fun ResultsScreen(
    viewModel : GradeViewModel,
    onBack    : () -> Unit
) {
    val context           = LocalContext.current
    val uiState           by viewModel.uiState.collectAsState()
    val snackbarHostState = remember { SnackbarHostState() }

    // Show a toast when export completes
    LaunchedEffect(uiState.exportSuccess) {
        if (uiState.exportSuccess) {
            Toast.makeText(context, "Results exported successfully!", Toast.LENGTH_LONG).show()
            viewModel.resetExportState()
        }
    }

    // Show a toast when an error occurs
    LaunchedEffect(uiState.errorMessage) {
        uiState.errorMessage?.let { msg ->
            Toast.makeText(context, msg, Toast.LENGTH_LONG).show()
            viewModel.clearError()
        }
    }

    Scaffold(
        topBar = {
            TopAppBar(
                title           = { Text("Results", color = OffWhite) },
                navigationIcon  = {
                    TextButton(onClick = onBack) {
                        Text("Back", color = BluePrimary)
                    }
                },
                colors = TopAppBarDefaults.topAppBarColors(containerColor = DarkSurface)
            )
        },
        snackbarHost   = { SnackbarHost(snackbarHostState) },
        containerColor = DarkBg
    ) { padding ->

        Column(
            modifier = Modifier
                .fillMaxSize()
                .padding(padding)
                .padding(horizontal = 16.dp)
        ) {
            Spacer(modifier = Modifier.height(12.dp))

            SummaryCard(students = uiState.calculatedStudents)

            Spacer(modifier = Modifier.height(12.dp))

            LazyColumn(
                modifier            = Modifier.weight(1f),
                verticalArrangement = Arrangement.spacedBy(10.dp),
                contentPadding      = PaddingValues(bottom = 16.dp)
            ) {
                items(uiState.calculatedStudents) { student ->
                    ResultCard(student)
                }
            }

            // Export button — triggers ShareSheet, no save picker needed
            if (uiState.isExporting) {
                Box(
                    modifier         = Modifier.fillMaxWidth(),
                    contentAlignment = Alignment.Center
                ) {
                    CircularProgressIndicator(color = BluePrimary)
                }
            } else {
                Button(
                    onClick  = { viewModel.exportResults(context) },  // ← simple!
                    modifier = Modifier
                        .fillMaxWidth()
                        .navigationBarsPadding()
                        .padding(vertical = 12.dp)
                        .height(54.dp),
                    shape  = RoundedCornerShape(14.dp),
                    colors = ButtonDefaults.buttonColors(containerColor = BlueDeep)
                ) {
                    Text(
                        "Export to Excel",
                        style = MaterialTheme.typography.labelLarge,
                        color = White
                    )
                }
            }
        }
    }
}

